var WEXNZ = require('./wexnz.js')

var wexnz = new WEXNZ('YOUR-KEY', 'YOUR-SECRET')

wexnz.getInfo(function(err, data) {
  console.log('\nGet Info: ')
  if (!err) console.log(data)
  else console.log(err)
})

wexnz.ticker({ pair: 'btc_usd' }, function(err, data) {
  console.log('\nTicker: ')
  if (!err) console.log(data)
  else console.log(err)
})

